SELECT EstrazioneDatiPerCompilazioneTemplateNapa.upc AS chiave_, EstrazioneDatiPerCompilazioneTemplateNapa.[Document No_], EstrazioneDatiPerCompilazioneTemplateNapa.No_, EstrazioneDatiPerCompilazioneTemplateNapa.[Model Item No_], EstrazioneDatiPerCompilazioneTemplateNapa.[Description 2], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 01], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 02], Str$(Sum([qty_val])) AS qty_txt_, Sum(EstrazioneDatiPerCompilazioneTemplateNapa.qty_val) AS qty_val_, EstrazioneDatiPerCompilazioneTemplateNapa.UPC, Sum(EstrazioneDatiPerCompilazioneTemplateNapa.Amt) AS Amt_
FROM EstrazioneDatiPerCompilazioneTemplateNapa
GROUP BY EstrazioneDatiPerCompilazioneTemplateNapa.upc, EstrazioneDatiPerCompilazioneTemplateNapa.[Document No_], EstrazioneDatiPerCompilazioneTemplateNapa.No_, EstrazioneDatiPerCompilazioneTemplateNapa.[Model Item No_], EstrazioneDatiPerCompilazioneTemplateNapa.[Description 2], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 01], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 02], EstrazioneDatiPerCompilazioneTemplateNapa.UPC;

